class Paj:

  def __init__(self, typ, fyllning, portioner):
    self.typ = typ
    self.fyllning = fyllning
    self.antal_portioner = portioner

  def __str__(self):
    return self.fyllning + "s" + self.typ + " för "+ str(self.antal_portioner) + " pers."

  def tillagningstid(self):
    if self.typ == "smulpaj":
      print("Ca 20 minuter på 225 C")
    elif self.fyllning == "pekannöter" or self.fyllning == "äpple":
      print("Ca 35-40 minuter på 200 C")
    else:
      print("Ca 25-30 minuter på 200 C")

  def nytt_antal(self, nytt_antal):
    self.antal_portioner = nytt_antal
